#include<bits/stdc++.h>
using namespace std;
int a[10000010];
long long jc[10000010],ny[10000010];
const long long mod=998244353;
long long fastpow(long long x,long long y)
{
    long long ans=1;
    while(y)
    {
        if(y&1)
        {
            ans=ans*x%mod;
        }
        x=x*x%mod;
        y/=2;
    }
    return ans;
}
long long C(long long n,long long m)
{
    return jc[n]*ny[m]%mod*ny[n-m]%mod;
}
int main()
{
    jc[0]=ny[0]=1;
    for(int i=1;i<=10000000;i++)
    {
        jc[i]=jc[i-1]*i%mod;
    }
    ny[10000000]=fastpow(jc[10000000],mod-2);
    for(int i=9999999;i>=1;i--)
    {
        ny[i]=ny[i+1]*(i+1)%mod;
    }
    int t;
    scanf("%d",&t);
    while(t--)
    {
        int n,m;
        scanf("%d%d",&n,&m);
        m--;
        int cnt=0;
        for(int i=1;i<=n;i++)
        {
            scanf("%d",&a[i]);
            if(a[i]<=a[i-1])
            {
                cnt++;
            }
        }
        if(m<cnt)
        {
            printf("0\n");
            continue;
        }
        long long ans=0;
        for(long long i=0;i<=m-cnt;i++)
        {
            ans+=C(n-1-cnt,i);
            ans%=mod;
        }
        printf("%lld\n",ans);
    }
    return 0;
}
